// Definir la función (aún no hace nada)
function saludar() {
  console.log("¡Bienvenida a tu app!");
}

// Llamarla: ahora sí se ejecuta
saludar();   // ¡Bienvenida a tu app!

function saludar(nombre) {
  console.log("¡Hola, " + nombre + "!");
}

saludar("Lucía");   // ¡Hola, Lucía!
saludar("Marta");   // ¡Hola, Marta!  (misma función, otro dato)

function conIva(precio) {
  return precio * 1.21;   // entrega el resultado
}

const total = conIva(100);   // guarda 121 en total
console.log(total);          // 121
console.log(conIva(50));     // 60.5

function mediaDeNotas(a, b, c) {
  return (a + b + c) / 3;
}

console.log(mediaDeNotas(4, 5, 3));   // 4
console.log(mediaDeNotas(2, 2, 5));   // 3
// Un solo sitio que arreglar si cambia la fórmula

function avisoDeRiego(dias) {
  if (dias > 3) return "¡Riégala ya!";
  if (dias > 1) return "Pronto tocará";
  return "Todo bien";
}

console.log(avisoDeRiego(5));   // ¡Riégala ya!
console.log(avisoDeRiego(2));   // Pronto tocará
console.log(avisoDeRiego(0));   // Todo bien

