function total(precio, cantidad) {
  return precio * cantidad;
}
console.log(total(8, 5));   // 40

function sumar(numeros) {
  let total = 0;
  for (const n of numeros) {
    total = total + n;
  }
  return total;
}
console.log(sumar([12, 8, 20, 5]));   // 45
